section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "testing-patterns-output",
  "required": [
    "strategy_doc",
    "pyramid_target",
    "data_pattern",
    "ui_pattern",
    "forbidden_seen"
  ],
  "properties": {
    "strategy_doc": {
      "description": "Markdown rubric path."
    },
    "pyramid_target": {
      "description": "Target ratios {unit, integration, e2e}."
    },
    "data_pattern": {
      "description": "Chosen test-data pattern per layer."
    },
    "ui_pattern": {
      "description": "POM if UI tests exist, else `none`."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
